import { chromium } from 'playwright';
import fs from 'fs';

const COOKIES_PATH = 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\devops_cookies.json';
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

async function run() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_PATH, 'utf-8'));

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();
  await context.addCookies(cookies);

  const page = await context.newPage();

  console.log('Navigating to pipeline page...');
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });

  // Take screenshot to see current state
  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\step1_pipeline.png' });
  console.log('Screenshot saved: step1_pipeline.png');
  console.log('Page title:', await page.title());
  console.log('Page URL:', page.url());

  // Check if we're logged in or need to login
  const pageContent = await page.content();
  if (pageContent.includes('login') || pageContent.includes('扫码') || page.url().includes('login')) {
    console.log('NOT LOGGED IN - Cookie may be expired');
    await browser.close();
    process.exit(1);
  }

  // Look for "启动新构建" button
  console.log('Looking for start build button...');

  // Try various selectors
  const buttonSelectors = [
    'button:has-text("启动新构建")',
    'button:has-text("运行")',
    'button:has-text("触发")',
    '[class*="run"]',
    'button:has-text("Run")',
  ];

  let startBtn = null;
  for (const sel of buttonSelectors) {
    try {
      const el = await page.$(sel);
      if (el) {
        startBtn = el;
        console.log('Found button with selector:', sel);
        break;
      }
    } catch(e) {}
  }

  if (!startBtn) {
    // Print all buttons for debugging
    const buttons = await page.$$eval('button', btns => btns.map(b => b.textContent?.trim()).filter(t => t));
    console.log('Available buttons:', JSON.stringify(buttons));

    // Also check links
    const links = await page.$$eval('a', as => as.map(a => ({ text: a.textContent?.trim(), href: a.href })).filter(a => a.text));
    console.log('Available links:', JSON.stringify(links.slice(0, 20)));

    await browser.close();
    process.exit(2);
  }

  await startBtn.click();
  console.log('Clicked start button');
  await page.waitForTimeout(2000);
  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\step2_after_click.png' });
  console.log('Screenshot saved: step2_after_click.png');

  // Look for dest variable field and change it to 1v1_qa
  console.log('Looking for dest variable...');

  // Try to find input fields
  const inputs = await page.$$eval('input', inputs => inputs.map(i => ({ 
    name: i.name, 
    placeholder: i.placeholder, 
    value: i.value,
    type: i.type 
  })));
  console.log('Available inputs:', JSON.stringify(inputs));

  // Look for dest input
  const destInputSelectors = [
    'input[name="dest"]',
    'input[placeholder*="dest"]',
    'input[value*="dest"]',
  ];

  let destInput = null;
  for (const sel of destInputSelectors) {
    try {
      const el = await page.$(sel);
      if (el) {
        destInput = el;
        console.log('Found dest input with selector:', sel);
        break;
      }
    } catch(e) {}
  }

  // If no direct match, look for label "dest" and find nearby input
  if (!destInput) {
    console.log('Trying label approach for dest...');
    // Find text "dest" and look for nearby input
    const destLabel = await page.$('text=dest');
    if (destLabel) {
      // Try sibling or parent's input
      destInput = await page.$('//label[contains(text(),"dest")]//following-sibling::input | //label[contains(text(),"dest")]/..//input');
      if (destInput) {
        console.log('Found dest input via label');
      }
    }
  }

  if (destInput) {
    await destInput.triple_click ? destInput.triple_click() : destInput.click({ clickCount: 3 });
    await destInput.fill('1v1_qa');
    console.log('Set dest to 1v1_qa');
  } else {
    console.log('Could not find dest input - will try to find all variable inputs in dialog');

    // Look for dialog/modal with variable inputs
    const dialogInputs = await page.$$('[role="dialog"] input, .modal input, [class*="dialog"] input, [class*="modal"] input');
    console.log('Dialog inputs count:', dialogInputs.length);

    for (let i = 0; i < dialogInputs.length; i++) {
      const info = await dialogInputs[i].evaluate(el => ({
        name: el.name,
        placeholder: el.placeholder,
        value: el.value,
        id: el.id
      }));
      console.log(`Dialog input ${i}:`, JSON.stringify(info));
    }
  }

  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\step3_variables.png' });

  // Look for submit/confirm button
  const confirmSelectors = [
    'button:has-text("确定")',
    'button:has-text("提交")',
    'button:has-text("确认")',
    'button:has-text("运行")',
    'button:has-text("启动")',
    'button[type="submit"]',
  ];

  let confirmBtn = null;
  for (const sel of confirmSelectors) {
    try {
      const el = await page.$(sel);
      if (el) {
        const isVisible = await el.isVisible();
        if (isVisible) {
          confirmBtn = el;
          console.log('Found confirm button with selector:', sel);
          break;
        }
      }
    } catch(e) {}
  }

  if (confirmBtn) {
    await confirmBtn.click();
    console.log('Clicked confirm button');
    await page.waitForTimeout(3000);
    await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\step4_after_confirm.png' });
    console.log('Screenshot saved: step4_after_confirm.png');

    // Get current URL to extract build number
    const currentUrl = page.url();
    console.log('Current URL after confirm:', currentUrl);

    // Look for build number in URL or page
    const buildMatch = currentUrl.match(/\/(\d+)$/);
    if (buildMatch) {
      console.log('BUILD NUMBER:', buildMatch[1]);
    }

    // Also check page for build number
    const pageText = await page.innerText('body').catch(() => '');
    const buildNumMatch = pageText.match(/#(\d+)/);
    if (buildNumMatch) {
      console.log('BUILD NUMBER from page:', buildNumMatch[1]);
    }
  } else {
    console.log('Could not find confirm button');
    const allBtns = await page.$$eval('button', btns => btns.map(b => ({ text: b.textContent?.trim(), visible: b.offsetParent !== null })));
    console.log('All buttons:', JSON.stringify(allBtns));
  }

  await browser.close();
  console.log('Done');
}

run().catch(err => {
  console.error('ERROR:', err.message);
  process.exit(1);
});

