import { chromium } from 'playwright';
import fs from 'fs';

const COOKIES_PATH = 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\devops_cookies.json';
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

async function run() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_PATH, 'utf-8'));

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();
  await context.addCookies(cookies);

  const page = await context.newPage();

  console.log('Navigating to pipeline page...');
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });

  // Click start build button
  await page.click('button:has-text("启动新构建")');
  console.log('Clicked start build button');
  await page.waitForTimeout(2000);

  // Dump the DOM structure to understand the variable inputs
  const domInfo = await page.evaluate(() => {
    // Find all input elements and their context
    const inputs = document.querySelectorAll('input');
    const result = [];
    for (const inp of inputs) {
      const parent = inp.parentElement;
      const grandParent = parent?.parentElement;
      result.push({
        value: inp.value,
        type: inp.type,
        placeholder: inp.placeholder,
        disabled: inp.disabled,
        readOnly: inp.readOnly,
        parentClass: parent?.className,
        grandParentClass: grandParent?.className,
        parentText: parent?.innerText?.substring(0, 100),
      });
    }
    return result;
  });

  console.log('All inputs:', JSON.stringify(domInfo, null, 2));

  // Find the structure: variables are likely key-value pairs
  // The "dest" label is a disabled input, the actual value input should be nearby
  // Let's look at the page structure around "dest"
  const varStructure = await page.evaluate(() => {
    // Find all inputs with value "dest" (these are the key labels)
    const destInputs = Array.from(document.querySelectorAll('input')).filter(i => i.value === 'dest');
    if (destInputs.length === 0) return { error: 'no dest input found' };

    const destInput = destInputs[0];
    // Walk up to find the row container
    let container = destInput.parentElement;
    for (let i = 0; i < 5; i++) {
      const allInputsInContainer = container.querySelectorAll('input');
      if (allInputsInContainer.length >= 2) {
        // Found a container with multiple inputs - return info
        const inputs = Array.from(allInputsInContainer).map(inp => ({
          value: inp.value,
          disabled: inp.disabled,
          readOnly: inp.readOnly,
          type: inp.type,
          placeholder: inp.placeholder,
        }));
        return { containerClass: container.className, inputs, html: container.innerHTML.substring(0, 500) };
      }
      container = container.parentElement;
      if (!container) break;
    }

    // Also check siblings
    const parent = destInput.parentElement;
    const siblings = parent ? Array.from(parent.parentElement?.children || []).map(el => ({
      tag: el.tagName,
      class: el.className,
      text: el.innerText?.substring(0, 50),
      inputCount: el.querySelectorAll('input').length
    })) : [];

    return { siblings, destParentHtml: parent?.outerHTML?.substring(0, 1000) };
  });

  console.log('Variable structure:', JSON.stringify(varStructure, null, 2));

  await browser.close();
}

run().catch(err => {
  console.error('ERROR:', err.message);
  console.error(err.stack);
  process.exit(1);
});

import { chromium } from 'playwright';
import fs from 'fs';

const COOKIES_PATH = 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\devops_cookies.json';
const PIPELINE_URL = 'https://devops.devcloud.ztgame.com/projects/yyzy/pipelines/p-f78c977835c84b71a6d58b4746cd1c4a';

async function run() {
  const cookies = JSON.parse(fs.readFileSync(COOKIES_PATH, 'utf-8'));

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext();
  await context.addCookies(cookies);

  const page = await context.newPage();

  console.log('Navigating to pipeline page...');
  await page.goto(PIPELINE_URL, { waitUntil: 'networkidle', timeout: 30000 });

  // Click start build button
  await page.click('button:has-text("启动新构建")');
  console.log('Clicked start build button');
  await page.waitForTimeout(2000);

  // The dest variable is the first ant-select dropdown in the dialog
  // Structure: disabled input with value="dest" + ant-select for the value
  // We need to find the ant-select that's next to the "dest" label

  // Get the current selected value of dest
  const destCurrentValue = await page.evaluate(() => {
    // Find the disabled input with value "dest"
    const destLabel = Array.from(document.querySelectorAll('input[disabled]')).find(i => i.value === 'dest');
    if (!destLabel) return null;

    // Go up to the flex row container
    const row = destLabel.closest('.flex.items-center.gap-3');
    if (!row) return null;

    // Find the ant-select in this row
    const select = row.querySelector('.ant-select');
    if (!select) return null;

    // Get the current displayed value
    const selectedValue = select.querySelector('.ant-select-selection-item')?.textContent?.trim();
    return { selectedValue, hasSelect: true };
  });

  console.log('Dest current value:', JSON.stringify(destCurrentValue));

  // Click on the ant-select for dest to open dropdown
  await page.evaluate(() => {
    const destLabel = Array.from(document.querySelectorAll('input[disabled]')).find(i => i.value === 'dest');
    const row = destLabel?.closest('.flex.items-center.gap-3');
    const select = row?.querySelector('.ant-select');
    select?.click();
  });

  console.log('Clicked dest select');
  await page.waitForTimeout(1000);

  // Type in the search box to filter options
  const searchInput = await page.$('.ant-select-open .ant-select-selection-search input');
  if (searchInput) {
    await searchInput.fill('1v1_qa');
    console.log('Typed 1v1_qa in search');
    await page.waitForTimeout(1000);
  } else {
    // Try the first visible search input that just became active
    const allSearchInputs = await page.$$('input[type="search"]');
    console.log('Search inputs found:', allSearchInputs.length);
    if (allSearchInputs.length > 0) {
      await allSearchInputs[0].fill('1v1_qa');
      console.log('Typed 1v1_qa in first search input');
      await page.waitForTimeout(1000);
    }
  }

  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\step_dest_dropdown.png' });

  // Check what options are available in the dropdown
  const dropdownOptions = await page.evaluate(() => {
    const options = document.querySelectorAll('.ant-select-dropdown .ant-select-item-option');
    return Array.from(options).map(o => o.textContent?.trim());
  });
  console.log('Dropdown options:', JSON.stringify(dropdownOptions));

  if (dropdownOptions.length > 0) {
    // Click the first option (should be 1v1_qa after filtering)
    const firstOption = await page.$('.ant-select-dropdown .ant-select-item-option');
    if (firstOption) {
      await firstOption.click();
      console.log('Selected option from dropdown');
    }
  } else {
    // Maybe it's a free-text input - just press Enter to confirm the typed value
    const searchInputs = await page.$$('input[type="search"]');
    if (searchInputs.length > 0) {
      await searchInputs[0].press('Enter');
      console.log('Pressed Enter to confirm 1v1_qa');
    }
  }

  await page.waitForTimeout(1000);

  // Check current state of dest
  const destAfterSet = await page.evaluate(() => {
    const destLabel = Array.from(document.querySelectorAll('input[disabled]')).find(i => i.value === 'dest');
    const row = destLabel?.closest('.flex.items-center.gap-3');
    const select = row?.querySelector('.ant-select');
    const selectedValue = select?.querySelector('.ant-select-selection-item')?.textContent?.trim();
    const inputValue = select?.querySelector('input')?.value;
    return { selectedValue, inputValue };
  });
  console.log('Dest after set:', JSON.stringify(destAfterSet));

  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\step_before_confirm.png' });

  // Click confirm/submit button
  const confirmSelectors = [
    'button:has-text("确定")',
    'button:has-text("提交")',
    'button:has-text("确认")',
    'button:has-text("启动")',
    '.ant-modal-footer button:last-child',
    'button[type="submit"]',
  ];

  let confirmed = false;
  for (const sel of confirmSelectors) {
    try {
      const el = await page.$(sel);
      if (el && await el.isVisible() && await el.isEnabled()) {
        const text = await el.textContent();
        console.log(`Found confirm button "${text}" with selector: ${sel}`);
        await el.click();
        confirmed = true;
        console.log('Clicked confirm button');
        break;
      }
    } catch(e) {}
  }

  if (!confirmed) {
    // List all visible buttons
    const allBtns = await page.$$eval('button', btns => 
      btns.filter(b => b.offsetParent !== null).map(b => ({ text: b.textContent?.trim(), type: b.type, disabled: b.disabled }))
    );
    console.log('Visible buttons:', JSON.stringify(allBtns));
  }

  await page.waitForTimeout(3000);
  await page.screenshot({ path: 'C:\\Users\\yyzypublic\\.openclaw\\workspace\\step_after_confirm.png' });

  const finalUrl = page.url();
  console.log('Final URL:', finalUrl);

  // Try to extract build number
  const buildIdMatch = finalUrl.match(/buildId=(b-[a-z0-9]+)/);
  if (buildIdMatch) {
    console.log('BUILD ID:', buildIdMatch[1]);
  }

  // Look for build number on page
  const pageText = await page.$eval('body', el => el.innerText).catch(() => '');
  const buildNumMatch = pageText.match(/#\d+/);
  if (buildNumMatch) {
    console.log('BUILD NUMBER on page:', buildNumMatch[0]);
  }

  // Check page title and any status indicators
  console.log('Page title:', await page.title());

  await browser.close();
  console.log('Done');
}

run().catch(err => {
  console.error('ERROR:', err.message);
  console.error(err.stack);
  process.exit(1);
});
